  ('promotion-6ec17a12-moex-00011', 'promotion-6ec17a12', 'promotion-6ec17a12-moex-114-3082b5f1', 'sub-promotion-6ec17a12-03', NULL, 'single_choice', '關於不當聯結禁止原則之敘述，下列何者錯誤？', '["行政處分之附款應與該處分之目的具有正當合理之關聯", "人民與行政機關締結雙務行政契約時，人民之給付與行政機關之給付應相當，並具有正當合理 之關聯", "依司法實務見解，汽車所有人繳清違規罰鍰後始得換發行車執照，並未牴觸不當聯結禁止原則", "以同意捐款勞軍，作為核發建築許可之條件，牴觸不當聯結禁止原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:42+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "131", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "海巡行政"}'::jsonb, NULL),
  ('promotion-6ec17a12-moex-00012', 'promotion-6ec17a12', 'promotion-6ec17a12-moex-114-3082b5f1', 'sub-promotion-6ec17a12-03', NULL, 'single_choice', '下列何者為行政法之一般法律原則？', '["依法行政原則", "罪刑法定原則", "契約自由原則", "不告不理原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:42+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "131", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "海巡行政"}'::jsonb, NULL),
  ('promotion-6ec17a12-moex-00013', 'promotion-6ec17a12', 'promotion-6ec17a12-moex-114-3082b5f1', 'sub-promotion-6ec17a12-03', NULL, 'single_choice', '依司法院大法官解釋意旨，關於行政機關之判斷餘地，司法審查之範圍不包括下列何者？', '["行政機關之判斷，是否出於錯誤事實認定或不完全資訊", "法律概念涉及事實關係時，其涵攝有無明顯錯誤", "作成判斷之行政機關，其組織是否合法且有判斷之權限", "行政機關所為公務人員考績處分，是否符合其績效表現"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:42+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "131", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "海巡行政"}'::jsonb, NULL),
  ('promotion-6ec17a12-moex-00014', 'promotion-6ec17a12', 'promotion-6ec17a12-moex-114-3082b5f1', 'sub-promotion-6ec17a12-03', NULL, 'single_choice', '關於行政法人之敘述，下列何者正確？', '["行政法人為行政機關，受其設置上級機關之指揮監督", "行政法人之人事、財政自主空間較大，完全排除國家人事、預算、會計及審計法規之適用", "地方自治團體得以自治條例設立地方行政法人", "行政法人依其人事管理規章所進用之人員，為公務人員 11030、11730 12330、12530 12830、13030 13130 14330、14530 30130、70130 71130"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:42+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "131", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "海巡行政"}'::jsonb, NULL),
  ('promotion-6ec17a12-moex-00015', 'promotion-6ec17a12', 'promotion-6ec17a12-moex-114-3082b5f1', 'sub-promotion-6ec17a12-03', NULL, 'single_choice', '關於地方自治團體組織之敘述，下列何者正確？', '["地方政府組織得以自治規則制定", "直轄市政府依據地方制度法擬訂其組織準則後，即可成立該組織", "直轄市政府設立果菜運銷有限公司應以自治條例定之", "市議會組織依憲法自律原則而成立"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:42+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "131", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "海巡行政"}'::jsonb, NULL),
  ('promotion-6ec17a12-moex-00016', 'promotion-6ec17a12', 'promotion-6ec17a12-moex-114-3082b5f1', 'sub-promotion-6ec17a12-03', NULL, 'single_choice', '關於行政程序法上職務協助之敘述，下列何者正確？', '["行政機關執行職務，由被請求機關協助執行較為經濟時，須組織法規有明文，始得請求職務協助", "被請求機關應考量協助之行為是否在其權限範圍內", "職務協助與委任、委託不同，屬於短暫性之關係，但仍會涉及權限之移轉", "職務協助須公告其協助之事項以及所提供之協助方式"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:42+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "131", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "海巡行政"}'::jsonb, NULL),
  ('promotion-6ec17a12-moex-00017', 'promotion-6ec17a12', 'promotion-6ec17a12-moex-114-3082b5f1', 'sub-promotion-6ec17a12-03', NULL, 'single_choice', '依公務人員考績法及實務見解，有關公務人員考績之敘述，下列何者正確？', '["行政機關對公務人員記大過處分，無懲處權時效之適用", "公務人員不服其服務機關所為考績丙等之評定，應以銓敘部為被告提起行政訴訟", "公務人員之年終考績丁等，效力為一次記兩大過免職", "考績應予免職人員，自確定之日起執行；未確定前，應先行停職"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:42+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "131", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "海巡行政"}'::jsonb, NULL)
